module barrel_shifter(  
    input [3:0] data_in,  
    input [1:0] shift_amount,  
    input direction, // 0 for left shift, 1 for right shift  
    output [3:0] data_out  
);  
    wire shifted_data = (direction == 0) ? (data_in << shift_amount) : (data_in >> shift_amount);
    assign data_out = shifted_data;  
endmodule
